import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box, MotionKeyframes } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

/**
 * Helper to map common condition strings to emojis if a specific icon isn't provided for the current state.
 */
const getConditionEmoji = (condition: string): string => {
  const c = (condition || '').toLowerCase();
  if (c.includes('sunny') || c.includes('clear')) return '☀️';
  if (c.includes('partly') || c.includes('cloud')) {
    if (c.includes('rain')) return '🌦️';
    return '⛅';
  }
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('shower')) return '🌧️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('fog') || c.includes('mist')) return '🌫️';
  return '🌡️';
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  const hasForecast = forecast && forecast.length > 0;

  return (
    <div 
      style={{ 
        animation: 'ggui-fadeIn 300ms ease-out',
        width: '100%' 
      }}
      role="region"
      aria-label={`Weather for ${city}`}
      aria-live="polite"
    >
      <MotionKeyframes />
      <Card 
        shadow="md" 
        padding={24} 
        radius="xl" 
        border={true}
        style={{ 
          background: 'var(--ggui-color-surfaceVariant)',
          maxWidth: '500px',
          margin: '0 auto'
        }}
      >
        <Stack direction="vertical" gap={16} align="stretch">
          {/* Header Section */}
          <Stack direction="vertical" gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface)">
              {city}
            </Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
              Current Conditions
            </Text>
          </Stack>

          {/* Current Temperature and Condition Summary */}
          <Stack direction="horizontal" align="center" justify="between">
            <Stack direction="vertical" gap={0}>
              <Text 
                variant="bodyLarge" 
                weight="bold" 
                style={{ fontSize: 'var(--ggui-font-size-4xl)', lineHeight: 1 }}
                color="var(--ggui-color-onSurface)"
              >
                {temperature}°{unit}
              </Text>
              <Text 
                variant="bodyLarge" 
                weight="medium" 
                color="var(--ggui-color-primary)"
              >
                {condition}
              </Text>
            </Stack>
            <Box 
              style={{ 
                fontSize: 'var(--ggui-font-size-4xl)',
                lineHeight: 1 
              }}
            >
              {getConditionEmoji(condition)}
            </Box>
          </Stack>

          {/* Key Metrics Row */}
          <Stack direction="horizontal" gap={32}>
            <Stack direction="vertical" gap={4}>
              <Text 
                variant="overline" 
                color="var(--ggui-color-onSurfaceVariant)"
              >
                HUMIDITY
              </Text>
              <Text 
                variant="body" 
                weight="semibold" 
                color="var(--ggui-color-onSurface)"
              >
                {humidity}%
              </Text>
            </Stack>
            <Stack direction="vertical" gap={4}>
              <Text 
                variant="overline" 
                color="var(--ggui-color-onSurfaceVariant)"
              >
                WIND
              </Text>
              <Text 
                variant="body" 
                weight="semibold" 
                color="var(--ggui-color-onSurface)"
              >
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>

          {/* Forecast Section */}
          {hasForecast && (
            <>
              <Divider 
                margin={20} 
                color="var(--ggui-color-outlineVariant)" 
              />
              <Stack 
                direction="horizontal" 
                justify="between" 
                wrap={true} 
                gap={16}
              >
                {forecast.map((item, index) => (
                  <Stack 
                    key={`${item.day}-${index}`} 
                    direction="vertical" 
                    align="center" 
                    gap={8}
                    style={{ minWidth: '60px', flex: '1 1 auto' }}
                  >
                    <Text 
                      variant="label" 
                      color="var(--ggui-color-onSurfaceVariant)"
                    >
                      {item.day}
                    </Text>
                    <Text 
                      style={{ fontSize: 'var(--ggui-font-size-xl)', lineHeight: 1 }}
                    >
                      {item.icon || getConditionEmoji('Clear')}
                    </Text>
                    <Stack direction="horizontal" gap={4}>
                      <Text 
                        variant="caption" 
                        weight="bold" 
                        color="var(--ggui-color-onSurface)"
                      >
                        {item.high}°
                      </Text>
                      <Text 
                        variant="caption" 
                        color="var(--ggui-color-onSurfaceVariant)"
                      >
                        {item.low}°
                      </Text>
                    </Stack>
                  </Stack>
                ))}
              </Stack>
            </>
          )}
        </Stack>
      </Card>
    </div>
  );
}
